diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index 33b66aeaffe6..cb593911709a 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2932,6 +2932,16 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
       return replaceInstUsesWith(*II, AbsSign);
     }

+    // fabs(fadd x, +/-0.0) -> fabs(x)
+    Value *AddX;
+    if (match(II->getArgOperand(0), m_c_FAdd(m_Value(AddX), m_AnyZeroFP()))) {
+      // Only fold if fadd has a single use (this fabs call)
+      if (II->getArgOperand(0)->hasOneUse()) {
+        CallInst *NewFabs = Builder.CreateUnaryIntrinsic(Intrinsic::fabs, AddX, II);
+        return replaceInstUsesWith(*II, NewFabs);
+      }
+    }
+
     [[fallthrough]];
   }
   case Intrinsic::ceil:

